import{_ as r,C as n,o as l,c,ao as o,j as t,a as d,E as a,w as i}from"./chunks/framework.yEt8qnMJ.js";const C=JSON.parse('{"title":"Choosing a backend","description":"","frontmatter":{},"headers":[],"relativePath":"guide/backends.md","filePath":"guide/backends.md","lastUpdated":null}'),p={name:"guide/backends.md"},h={class:"jldocstring custom-block",open:""},u={class:"jldocstring custom-block",open:""},g={class:"jldocstring custom-block",open:""},b={class:"jldocstring custom-block",open:""},k={class:"jldocstring custom-block",open:""};function y(m,e,f,w,x,T){const s=n("Badge");return l(),c("div",null,[e[20]||(e[20]=o('<h1 id="Choosing-a-backend" tabindex="-1">Choosing a backend <a class="header-anchor" href="#Choosing-a-backend" aria-label="Permalink to &quot;Choosing a backend {#Choosing-a-backend}&quot;">​</a></h1><p>Dewdrop separates two orthogonal choices:</p><ul><li><p><strong>Architecture</strong> (<code>arch = CPU()</code> / <code>GPU()</code>, set on the <a href="/Dewdrop.jl/dev/reference#Dewdrop.DewdropNetwork"><code>DewdropNetwork</code></a>) –- <em>where</em> the state lives.</p></li><li><p><strong>Execution backend</strong> (<code>backend = …</code>, passed to <code>solve</code>/<code>init</code>) –- <em>how</em> each step runs.</p></li></ul><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">solve</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(prob, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">FixedStep</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">); backend </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Fused</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">())</span></span></code></pre></div><p>All backends compute the <strong>same dynamics</strong>; they differ in speed and in whether the result is bit-reproducible. The default, <code>Auto</code>, picks a good one for you.</p><h2 id="The-backends-at-a-glance" tabindex="-1">The backends at a glance <a class="header-anchor" href="#The-backends-at-a-glance" aria-label="Permalink to &quot;The backends at a glance {#The-backends-at-a-glance}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">backend</th><th style="text-align:right;">what it does</th><th style="text-align:right;">bit-reproducible?</th><th style="text-align:right;">needs</th><th style="text-align:right;">use when</th></tr></thead><tbody><tr><td style="text-align:right;"><a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Auto"><code>Auto</code></a></td><td style="text-align:right;">picks the best available (see below)</td><td style="text-align:right;">inherits the chosen one</td><td style="text-align:right;">–-</td><td style="text-align:right;">the default; almost always</td></tr><tr><td style="text-align:right;"><a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Serial"><code>Serial</code></a></td><td style="text-align:right;">per-phase broadcasts, single-threaded dense phases</td><td style="text-align:right;"><strong>yes</strong>, allocation-free</td><td style="text-align:right;">–-</td><td style="text-align:right;">small nets, exact reproducibility, debugging</td></tr><tr><td style="text-align:right;"><a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Fused"><code>Fused</code></a></td><td style="text-align:right;">one fused pass/step: a tight threaded CPU loop, or the GPU megakernel</td><td style="text-align:right;"><strong>yes</strong> (bit-identical to <code>Serial</code>)</td><td style="text-align:right;">–-</td><td style="text-align:right;">large CPU nets; <strong>required</strong> on GPU and for <code>Heterogeneous</code>/<code>MultiModel</code></td></tr><tr><td style="text-align:right;"><a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Turbo"><code>Turbo</code></a></td><td style="text-align:right;">SIMD-vectorised dense step</td><td style="text-align:right;">no (spike-identical)</td><td style="text-align:right;"><code>using LoopVectorization</code> + a model with a Turbo specialization</td><td style="text-align:right;">maximum CPU throughput on supported, dense-dominated models</td></tr></tbody></table><h2 id="How-Auto-chooses" tabindex="-1">How <code>Auto</code> chooses <a class="header-anchor" href="#How-Auto-chooses" aria-label="Permalink to &quot;How `Auto` chooses {#How-Auto-chooses}&quot;">​</a></h2><p><a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Auto"><code>Auto</code></a> (the default) resolves to:</p><ul><li><p><code>Fused</code> on a <strong>GPU</strong> (the megakernel is the GPU path);</p></li><li><p><code>Fused</code> for a <strong><code>Heterogeneous</code>/<code>MultiModel</code></strong> model (per-neuron / per-group resolution needs it);</p></li><li><p><code>Fused</code> for a <strong>large multithreaded CPU</strong> network (<code>N ≥ 10_000</code>, <code>Threads.nthreads() &gt; 1</code>, canonical schedule) –- the threaded fused step is ~2× the per-phase <code>Serial</code> baseline and bit-identical;</p></li><li><p><code>Serial</code> otherwise (small / single-threaded CPU nets, where the per-phase path&#39;s low overhead wins).</p></li></ul><p><code>Turbo</code> is never chosen automatically (it is not bit-identical); request it explicitly.</p><h2 id="Performance" tabindex="-1">Performance <a class="header-anchor" href="#Performance" aria-label="Permalink to &quot;Performance {#Performance}&quot;">​</a></h2><p>Measured on the recurrent E/I AdEx benchmark (<code>test/brian/</code>), N = 16000, 5000 steps, Float32, vs Brian2&#39;s compiled-C++ standalone (CPU×1 = 0.347 s):</p><table tabindex="0"><thead><tr><th style="text-align:right;">backend</th><th style="text-align:right;">N = 16000</th><th style="text-align:right;">note</th></tr></thead><tbody><tr><td style="text-align:right;"><code>Serial</code> (1 thread)</td><td style="text-align:right;">~2.0 s</td><td style="text-align:right;">the multi-pass baseline</td></tr><tr><td style="text-align:right;"><code>Fused</code> (16 threads)</td><td style="text-align:right;"><strong>~0.38 s</strong></td><td style="text-align:right;">bit-identical; ≈ Brian2&#39;s compiled C++ (1.1×)</td></tr><tr><td style="text-align:right;"><code>Turbo</code> (SIMD)</td><td style="text-align:right;">~0.55 s (1 thread)</td><td style="text-align:right;">spike-identical; wins big on dense-dominated nets</td></tr><tr><td style="text-align:right;">Dewdrop <code>Fused</code> GPU</td><td style="text-align:right;">~0.09 s</td><td style="text-align:right;">1.7× faster than brian2cuda</td></tr></tbody></table><p>The <code>Fused</code> backend brings Dewdrop&#39;s CPU throughput to near-parity with hand-tuned compiled C++ with no dependency and <strong>no change in results</strong>; <code>Turbo</code> trades the <code>exp</code> ULP for SIMD and is fastest where the per-neuron compute dominates the sparse scatter.</p><h2 id="Reproducibility" tabindex="-1">Reproducibility <a class="header-anchor" href="#Reproducibility" aria-label="Permalink to &quot;Reproducibility {#Reproducibility}&quot;">​</a></h2><ul><li><p><code>Serial</code> and <code>Fused</code> are <strong>bit-identical</strong> to each other at any fixed thread count (the dense update is per-neuron-independent, so even threaded it is order-free). The one order-dependent operation is the <em>threaded</em> atomic synaptic scatter –- identical across backends, but not bit-reproducible across thread counts (run single-threaded for byte-exact reproducibility; the dynamics are statistically identical otherwise).</p></li><li><p><code>Turbo</code> is <strong>spike-identical</strong> but not bit-identical: SIMD <code>exp</code> (SLEEF) differs from scalar <code>libm</code> <code>exp</code> at the ULP level (<code>max|ΔV|</code> ~ 1e-5–1e-1 over a run).</p></li></ul><h2 id="GPU-spike-scatter-scatter-:auto" tabindex="-1">GPU spike scatter (<code>scatter = :auto</code>) <a class="header-anchor" href="#GPU-spike-scatter-scatter-:auto" aria-label="Permalink to &quot;GPU spike scatter (`scatter = :auto`) {#GPU-spike-scatter-scatter-:auto}&quot;">​</a></h2><p>On the GPU the synaptic scatter has two strategies, selected automatically by <code>scatter = :auto</code> (the default):</p><ul><li><p><strong><code>:edge</code></strong> — one thread per synapse. Saturates the device at small/medium sizes, but reads a source index for <em>every</em> edge each step (Θ(nedges) memory traffic regardless of firing), so once the connectome&#39;s index arrays spill the L2 cache the step becomes bandwidth-bound and a very large network degrades superlinearly.</p></li><li><p><strong><code>:compacted</code></strong> — processes only the out-edges of neurons that actually spiked (work ∝ spikes, for the usual sparse firing), at the cost of one per-step device→host sync. Far faster on large networks, a small loss on small ones (the sync dominates when the step is launch-bound).</p></li></ul><p><code>:auto</code> switches from <code>:edge</code> to <code>:compacted</code> once the connectome&#39;s index footprint exceeds about half the device L2 (the measured crossover), keeping the GPU step on the lower envelope at every size. On the CPU the scatter already walks only spiking rows, so <code>:auto</code> is always <code>:edge</code> there. Force a mode with <code>solve(...; scatter = :edge | :compacted)</code>; plastic (STDP) projections always use <code>:edge</code>.</p><h2 id="Guidance-the-advisor" tabindex="-1">Guidance (the advisor) <a class="header-anchor" href="#Guidance-the-advisor" aria-label="Permalink to &quot;Guidance (the advisor) {#Guidance-the-advisor}&quot;">​</a></h2><p>The performance advisor emits a one-off <code>@info</code> hint when a run could use a faster backend (e.g. a large CPU network that would benefit from <code>Turbo</code>). Silence it with <code>Dewdrop.set_advice!(false)</code> or <code>solve(...; advise = false)</code>.</p><h2 id="Deprecated-step-keyword" tabindex="-1">Deprecated <code>step</code> keyword <a class="header-anchor" href="#Deprecated-step-keyword" aria-label="Permalink to &quot;Deprecated `step` keyword {#Deprecated-step-keyword}&quot;">​</a></h2><p>The older <code>step = :auto | :serial | :fused | :turbo</code> keyword still works and maps onto the corresponding backend; prefer <code>backend = …</code>.</p>',25)),t("details",h,[t("summary",null,[e[0]||(e[0]=t("a",{id:"Dewdrop.SimBackend",href:"#Dewdrop.SimBackend"},[t("span",{class:"jlbinding"},"Dewdrop.SimBackend")],-1)),e[1]||(e[1]=d()),a(s,{type:"info",class:"jlObjectType jlType",text:"Type"})]),e[3]||(e[3]=o('<div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SimBackend</span></span></code></pre></div><p>Abstract supertype for execution backends –- <em>how</em> a step&#39;s dense per-neuron phases run, orthogonal to the architecture (<em>where</em> the state lives). See <a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Auto"><code>Auto</code></a>, <a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Serial"><code>Serial</code></a>, <a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Fused"><code>Fused</code></a> and <a href="/Dewdrop.jl/dev/guide/backends#Dewdrop.Turbo"><code>Turbo</code></a>.</p>',2)),a(s,{type:"info",class:"source-link",text:"source"},{default:i(()=>[...e[2]||(e[2]=[t("a",{href:"https://github.com/brendanjohnharris/Dewdrop.jl/blob/main/src/Backends.jl#L7-L13",target:"_blank",rel:"noreferrer"},"source",-1)])]),_:1})]),t("details",u,[t("summary",null,[e[4]||(e[4]=t("a",{id:"Dewdrop.Auto",href:"#Dewdrop.Auto"},[t("span",{class:"jlbinding"},"Dewdrop.Auto")],-1)),e[5]||(e[5]=d()),a(s,{type:"info",class:"jlObjectType jlType",text:"Type"})]),e[7]||(e[7]=o('<div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Auto</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre></div><p>The default backend: the advisor picks the best available for the architecture, network size, and loaded extensions –- <code>Fused</code> on a GPU, <code>Fused</code> for a large multithreaded CPU network or a heterogeneous/multi-type model, otherwise <code>Serial</code>. Override explicitly with <code>Serial</code>/<code>Fused</code>/<code>Turbo</code>.</p>',2)),a(s,{type:"info",class:"source-link",text:"source"},{default:i(()=>[...e[6]||(e[6]=[t("a",{href:"https://github.com/brendanjohnharris/Dewdrop.jl/blob/main/src/Backends.jl#L16-L22",target:"_blank",rel:"noreferrer"},"source",-1)])]),_:1})]),t("details",g,[t("summary",null,[e[8]||(e[8]=t("a",{id:"Dewdrop.Serial",href:"#Dewdrop.Serial"},[t("span",{class:"jlbinding"},"Dewdrop.Serial")],-1)),e[9]||(e[9]=d()),a(s,{type:"info",class:"jlObjectType jlType",text:"Type"})]),e[11]||(e[11]=o('<div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Serial</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre></div><p>The per-phase broadcast engine: single-threaded dense phases, <strong>bit-reproducible and allocation-free</strong>. The predictable baseline –- best for small networks, exact reproducibility, and debugging. (The sparse scatter is still threaded when <code>Threads.nthreads() &gt; 1</code>, as on every backend.)</p>',2)),a(s,{type:"info",class:"source-link",text:"source"},{default:i(()=>[...e[10]||(e[10]=[t("a",{href:"https://github.com/brendanjohnharris/Dewdrop.jl/blob/main/src/Backends.jl#L25-L31",target:"_blank",rel:"noreferrer"},"source",-1)])]),_:1})]),t("details",b,[t("summary",null,[e[12]||(e[12]=t("a",{id:"Dewdrop.Fused",href:"#Dewdrop.Fused"},[t("span",{class:"jlbinding"},"Dewdrop.Fused")],-1)),e[13]||(e[13]=d()),a(s,{type:"info",class:"jlObjectType jlType",text:"Type"})]),e[15]||(e[15]=o('<div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Fused</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre></div><p>One fused pass per step: on the CPU a tight, threaded plain-Julia loop over neurons; on a GPU the KernelAbstractions megakernel. <strong>Bit-identical</strong> to <code>Serial</code> (same hooks, same order, same <code>libm</code>), and faster at scale (it collapses the ~10 dense phases into a single pass and threads it). The recommended performance backend; required for heterogeneous (<code>Heterogeneous</code>) and multi-type (<code>MultiModel</code>) models.</p>',2)),a(s,{type:"info",class:"source-link",text:"source"},{default:i(()=>[...e[14]||(e[14]=[t("a",{href:"https://github.com/brendanjohnharris/Dewdrop.jl/blob/main/src/Backends.jl#L34-L42",target:"_blank",rel:"noreferrer"},"source",-1)])]),_:1})]),t("details",k,[t("summary",null,[e[16]||(e[16]=t("a",{id:"Dewdrop.Turbo",href:"#Dewdrop.Turbo"},[t("span",{class:"jlbinding"},"Dewdrop.Turbo")],-1)),e[17]||(e[17]=d()),a(s,{type:"info",class:"jlObjectType jlType",text:"Type"})]),e[19]||(e[19]=o('<div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Turbo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre></div><p>A SIMD-vectorised fused loop (via LoopVectorization). The <strong>fastest CPU backend</strong> –- it vectorises the membrane <code>exp</code>, reaching compiled-C++ throughput. CPU-only; requires <code>using LoopVectorization</code> and a model that provides a Turbo specialization (see the model-support table in the docs). <strong>Not bit-identical</strong>: SIMD <code>exp</code> differs from scalar <code>libm</code> at the ULP level, so results are spike-identical but not bit-reproducible (hence opt-in, never an <code>Auto</code> default).</p>',2)),a(s,{type:"info",class:"source-link",text:"source"},{default:i(()=>[...e[18]||(e[18]=[t("a",{href:"https://github.com/brendanjohnharris/Dewdrop.jl/blob/main/src/Backends.jl#L45-L53",target:"_blank",rel:"noreferrer"},"source",-1)])]),_:1})])])}const D=r(p,[["render",y]]);export{C as __pageData,D as default};
